import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Portail client","description":"","frontmatter":{},"headers":[],"relativePath":"fr/advanced/customer-portal.md","filePath":"fr/advanced/customer-portal.md"}'),l={name:"fr/advanced/customer-portal.md"};function r(o,e,s,c,u,d){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="portail-client" tabindex="-1">Portail client <a class="header-anchor" href="#portail-client" aria-label="Permalink to &quot;Portail client&quot;">​</a></h1><p>Le portail client permet a vos clients de consulter et payer leurs factures en ligne via une interface securisee a votre image.</p><h2 id="comment-ca-fonctionne" tabindex="-1">Comment ca fonctionne <a class="header-anchor" href="#comment-ca-fonctionne" aria-label="Permalink to &quot;Comment ca fonctionne&quot;">​</a></h2><p>Lorsque vous envoyez une facture, un <strong>lien de paiement</strong> unique est genere. Lorsque votre client clique sur ce lien, il accede au portail client ou il peut :</p><ol><li><strong>Consulter la facture</strong> -- Voir tous les details, lignes et totaux</li><li><strong>Telecharger le PDF</strong> -- Obtenir une copie de la facture</li><li><strong>Payer en ligne</strong> -- Effectuer le paiement via le portail</li><li><strong>Confirmer le paiement</strong> -- Attester d&#39;un virement bancaire</li></ol><h2 id="fonctionnalites-du-portail" tabindex="-1">Fonctionnalites du portail <a class="header-anchor" href="#fonctionnalites-du-portail" aria-label="Permalink to &quot;Fonctionnalites du portail&quot;">​</a></h2><h3 id="vue-de-la-facture" tabindex="-1">Vue de la facture <a class="header-anchor" href="#vue-de-la-facture" aria-label="Permalink to &quot;Vue de la facture&quot;">​</a></h3><p>Le portail affiche une vue claire et personnalisee de la facture comprenant :</p><ul><li>Le logo et l&#39;image de marque de votre entreprise</li><li>Le numero et la date de la facture</li><li>Les lignes avec descriptions et montants</li><li>La ventilation de la TVA</li><li>Le montant total du</li><li>La date d&#39;echeance</li></ul><h3 id="paiement" tabindex="-1">Paiement <a class="header-anchor" href="#paiement" aria-label="Permalink to &quot;Paiement&quot;">​</a></h3><p>Les clients peuvent payer directement via le portail. Lorsque le paiement est confirme, le statut de la facture dans votre tableau de bord est automatiquement mis a jour a <strong>Payee</strong>.</p><h3 id="image-de-marque" tabindex="-1">Image de marque <a class="header-anchor" href="#image-de-marque" aria-label="Permalink to &quot;Image de marque&quot;">​</a></h3><p>Le portail client utilise l&#39;image de marque de votre entreprise :</p><ul><li>Logo de l&#39;entreprise</li><li>Couleur d&#39;accentuation</li><li>Informations de l&#39;entreprise</li></ul><p>Cela cree une experience professionnelle et coherente pour vos clients.</p><h2 id="securite-d-acces" tabindex="-1">Securite d&#39;acces <a class="header-anchor" href="#securite-d-acces" aria-label="Permalink to &quot;Securite d&#39;acces&quot;">​</a></h2><p>Chaque lien du portail est :</p><ul><li><strong>Unique</strong> -- Genere par facture</li><li><strong>Base sur un jeton</strong> -- Securise avec un jeton d&#39;acces unique</li><li><strong>Specifique a la facture</strong> -- N&#39;affiche que la facture concernee</li></ul><p>Les clients n&#39;ont pas besoin d&#39;un compte MyCompanyDesk pour consulter et payer leurs factures.</p><h2 id="suivi-des-evenements-client" tabindex="-1">Suivi des evenements client <a class="header-anchor" href="#suivi-des-evenements-client" aria-label="Permalink to &quot;Suivi des evenements client&quot;">​</a></h2><p>MyCompanyDesk suit les interactions des clients avec le portail :</p><ul><li>Quand le client ouvre la facture</li><li>Quand il telecharge le PDF</li><li>Quand il initie un paiement</li><li>Quand le paiement est confirme</li></ul><p>Cela vous aide a comprendre l&#39;engagement de vos clients et a effectuer des relances efficacement.</p><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Incluez une note personnelle dans votre e-mail de facture pour encourager l&#39;utilisation du portail</li><li>Le portail fonctionne sur tous les appareils -- mobile, tablette et ordinateur</li><li>Les confirmations de paiement sont envoyees a vous et au client</li><li>Consultez l&#39;historique des evenements client sur la page de detail de la facture pour voir les interactions avec le portail</li></ul>',25)])])}const f=a(l,[["render",r]]);export{m as __pageData,f as default};
